func TestEnumShape(t *testing.T) {
	t.Run("NewFromString_SQUARE", func(t *testing.T) {
		t.Parallel()
		val, err := NewShapeFromString("SQUARE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Shape("SQUARE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_CIRCLE", func(t *testing.T) {
		t.Parallel()
		val, err := NewShapeFromString("CIRCLE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Shape("CIRCLE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_TRIANGLE", func(t *testing.T) {
		t.Parallel()
		val, err := NewShapeFromString("TRIANGLE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Shape("TRIANGLE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewShapeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewShapeFromString("SQUARE")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

